import asyncio
import websockets

class GameServer:
    def __init__(self):
        self.inventory = {}

    async def start(self):
        server = await asyncio.start_server(self.handle_client, 'localhost', 8000)
        print('Server started')
        await server.serve_forever()

    async def handle_client(self, websocket, path):
        player_id = int(path.split('/')[1])
        self.inventory[player_id] = {}

        while True:
            message = await websocket.recv()
            if message == 'GET_INVENTORY':
                inventory = self.inventory[player_id].copy()
                await websocket.send(json.dumps(inventory))
            elif message.startswith('TRADE'):
                trade_message = json.loads(message)
                sender_id = trade_message['sender']
                recipient_id = trade_message['recipient']
                item_id = trade_message['item']
                self.inventory[sender_id].pop(item_id, None)
                self.inventory[recipient_id][item_id] = True
            elif message == 'UPDATE_OWNERSHIP':
                await websocket.send(json.dumps({'status': 'success'}))

loop = asyncio.get_event_loop()
server = GameServer()
loop.create_task(server.start())
loop.run_forever()